#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;
bool isOdd(int num)
{
    return num % 2 == 1;
}
void printer(vector<int> data)
{
    reverse(data.begin(), data.end());
    for (int i = 0; i < data.size(); i++)
    {
        /* code */
        cout << data[i] << ' ';
    }
}
int main()
{
    int num = 20;
    cin >> num;
    vector<int> arr = {20};
    while (num != 1)
    {
        if (isOdd(num))
        {
            num = num * 3 + 1;
        }
        else
        {
            num = num / 2;
        }
        arr.push_back(num);
    }
    printer(arr);
}
